func TestNewServicePropagatesLoaderError(t *testing.T) {
	wantErr := errors.New("boom")

	svc, err := NewService(LoaderFunc(func() (*AppConfig, error) {
		return nil, wantErr
	}))
	if !errors.Is(err, wantErr) {
